### Replace: src/repos.ts (full rewrite)
New `FlowStore` object with these methods (matching the table in the spec):

```ts
export const FlowStore = {
  findById(id: string): FlowDoc | null {
    const path = `${FLOWS_DIR}/${id}.json`;
    if (!existsSync(path)) return null;
    return JSON.parse(readFileSync(path, "utf-8"));
  },

  list(): FlowDoc[] {
    if (!existsSync(FLOWS_DIR)) return [];
    return readdirSync(FLOWS_DIR)
      .filter(f => f.endsWith(".json"))
      .map(f => JSON.parse(readFileSync(join(FLOWS_DIR, f), "utf-8")));
  },

  countByPrefix(prefix: string): number {
    return FlowStore.list().filter(d => d.id.startsWith(prefix)).length;
  },

  create(doc): FlowDoc {
    const now = new Date().toISOString();
    const full: FlowDoc = { ...doc, created_at: now, updated_at: now };
    write(full.id, full);
    return full;
  },

  update(id, patch): FlowDoc {
    const cur = FlowStore.findById(id);
    if (!cur) throw new Error(`Flow not found: ${id}`);
    const next = { ...cur, ...patch, updated_at: new Date().toISOString() };
    write(id, next);
    return next;
  },

  // Scope methods
  getLocal(id, path?) { return getScope(id, "local", path); },
  setLocal(id, path, value) { setScope(id, "local", path, value); },
  replaceLocal(id, data) { replaceScope(id, "local", data); },
  deleteLocal(id) { replaceScope(id, "local", {}); },
  // (same for global)
};
```

Helpers (file-private):
- `write(id, doc)` — `writeFileSync(path, JSON.stringify(doc, null, 2))`
- `walkPath(obj, "a.b.c")` — returns deep value or null
- `setPath(obj, "a.b.c", value)` — mutates obj, creates intermediates
- `getScope/setScope/replaceScope` — read flow, mutate `local`/`global`, write back, refresh updated_at

